pub fn get_fulfilled_original_transactions(
    &self,
    current_block: u64,
) -> Result<Vec<(Arc<ValidPoolTransaction<EthPooledTransaction<TransactionSigned>>>, AsyncTxMetadata<T>)>, AsyncConversionError> {
    self.fulfilled_entries(current_block)
        .into_iter()
        .map(|metadata| {
            let tx_signed = Self::convert_original_to_signed(&metadata.original_tx);
            let pool_tx = Self::convert_signed_to_pool_tx(tx_signed)?;
            Ok((pool_tx, metadata))
        })
        .collect()
}

fn convert_original_to_signed(original_tx: &OriginalTransaction) -> TransactionSigned {
    match original_tx {
        OriginalTransaction::Legacy(signed_tx) => signed_tx.clone().into(),
        OriginalTransaction::Eip1559(signed_tx) => signed_tx.clone().into(),
        OriginalTransaction::Scheduled(signed_tx) => signed_tx.clone().into(),
        OriginalTransaction::Passkey(signed_tx) => signed_tx.clone().into(),
        OriginalTransaction::AsyncSettlement(signed_tx) => signed_tx.clone().into(),
    }
}
